INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8ed35e25-d3a4-44b0-aa78-ae037b102c02',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Experiment Tracking — Logging, Artifacts, and Run Comparison That Actually Scales$escape$,
  $escape$Every wandb run starts with `wandb.init()`, where `project` and `config` are your first-class citizens. Pass hyperparameters via `config` — not hardcoded — so they're queryable in the UI later. Use `wandb.log()` inside your training loop to stream metrics step-by-step; the `step` parameter lets you align multiple metrics on the same x-axis across runs.

For artifacts, `wandb.Artifact` gives you versioned, content-addressed storage. Log a model checkpoint with `artifact.add_file()` then `run.log_artifact()` — wandb computes a digest so identical files aren't re-uploaded. Tag artifacts with `aliases` like `best` or `production` to create a promotion pipeline without copying files.

Run comparison lives in the Table view: group by config keys (e.g. `learning_rate`, `optimizer`), then plot parallel coordinates to spot which hyperparameter ranges dominate your validation loss. Use `wandb.summary` to pin a single scalar — like best val accuracy — that survives across the full run history and surfaces cleanly in the runs table for sorting.$escape$,
  $escape$import wandb

run = wandb.init(
    project="image-classifier",
    config={"lr": 1e-3, "epochs": 20, "optimizer": "adamw", "batch_size": 64}
)

for epoch in range(run.config.epochs):
    train_loss = train_one_epoch()
    val_acc = evaluate()
    wandb.log({"train/loss": train_loss, "val/accuracy": val_acc}, step=epoch)

wandb.summary["best_val_accuracy"] = best_val_acc

artifact = wandb.Artifact("model-checkpoint", type="model")
artifact.add_file("checkpoint.pt")
run.log_artifact(artifact, aliases=["best"])

run.finish()$escape$,
