INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f03a460-a6cf-4757-84f4-ed685298f471',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb + DVC — Wiring Data Versioning Into Your Experiment Runs$escape$,
  $escape$DVC and wandb solve different halves of the reproducibility problem. DVC owns your data files, pipeline stages, and `params.yaml` — wandb owns run history, metric curves, and model artifacts. Wire them together by reading `params.yaml` inside each DVC stage and passing it directly to `wandb.init(config=params)`. Now every `dvc repro` produces a tracked wandb run stamped with the exact hyperparams used.

For remote storage, keep large datasets in your DVC remote (S3/GCS via `dvc push/pull`) and push model checkpoints to wandb Artifacts — the two systems don't overlap. Use `dvc params diff HEAD~1` to see what changed between pipeline runs, then cross-reference against wandb's run comparison panel to see how metrics shifted.

The critical integration point: write DVC stage `outs:` to disk *and* log them via `wandb.log()`. DVC's file-level content hashing gives you exact reproducibility and cache invalidation; wandb's UI gives you cross-run analysis and collaboration. Neither tool alone gives you both. Tag each wandb run with the active DVC commit via `wandb.run.tags` so you can always trace a metric back to the pipeline version that produced it.$escape$,
  $escape$import json, yaml, wandb

with open("params.yaml") as f:
    params = yaml.safe_load(f)["train"]

run = wandb.init(project="my-model", config=params,
                 tags=["dvc"])
wandb.run.tags += ("dvc-" + open(".dvc/tmp/run-cache").read()[:7],)

model = train(lr=params["lr"], epochs=params["epochs"])
metrics = evaluate(model)

wandb.log(metrics)

with open("metrics/scores.json", "w") as f:
    json.dump(metrics, f)

model.save("models/model.pkl")
wandb.save("models/model.pkl")
run.finish()$escape$,
  $escape$python$escape$,
