INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f8686a87-a400-415e-afba-0f21dba8f695',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Model Registry — Staging, Production, and Approval Workflows$escape$,
  $escape$wandb's Model Registry centralizes versioned model artifacts with explicit lifecycle stages. When you log a model via `wandb.log_artifact()`, it lands as a candidate version. From there, you promote it through stages — `staging` and `production` — using the Registry UI or the API.

Each model version is an immutable artifact linked to the run that produced it, giving you full lineage: hyperparams, metrics, dataset version, and code commit. Promotion isn't automatic — Registry supports approval workflows where designated reviewers must sign off before a version reaches `production`. This prevents hot-fix accidents and creates an auditable trail.

Programmatically, use `wandb.Api()` to fetch a registered model and update its aliases. Aliases like `staging` and `production` are mutable pointers; the underlying artifact version never changes. Downstream systems (CI pipelines, inference servers) pin to an alias, so promoting is a one-line alias reassignment — no redeployment of config files needed. Combine this with webhook triggers on stage transitions to automate downstream deployment.$escape$,
  $escape$import wandb

api = wandb.Api()

# Link a logged artifact to the Model Registry
run = wandb.init(project="fraud-detection")
artifact = run.use_artifact("fraud-model:v12", type="model")

# Promote to staging (run this after validation)
registered_model = api.artifact("team/fraud-detection/fraud-model:v12")
registered_model.aliases.append("staging")
registered_model.save()

# After approval workflow completes, promote to production
registered_model.aliases = [a for a in registered_model.aliases if a != "staging"]
registered_model.aliases.append("production")
registered_model.save()

wandb.finish()$escape$,
  $escape$python$escape$,
