INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '759b11eb-887e-4778-b954-d7fe0c9a2838',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Artifacts — Versioning ONNX Exports and Tracking Inference Benchmarks$escape$,
  $escape$ONNX gives you a framework-agnostic snapshot of your model — but without provenance, that .onnx file is just a black box. wandb closes that gap. After exporting via torch.onnx.export(), log the file as a wandb.Artifact with type='model' and attach the originating run's config as metadata. This links the ONNX graph back to the exact hyperparameters, dataset version, and training run that produced it. From there, run onnxruntime.InferenceSession on the exported file and log latency and throughput with wandb.log() alongside the original PyTorch baseline — now you have a side-by-side latency comparison tracked across every export. Tag the artifact as 'production' via the wandb Model Registry when it passes your latency threshold. Downstream consumers (serving, mobile pipelines) can pull the artifact by alias rather than filename, so promotions are atomic and auditable. Use wandb.use_artifact() in your inference benchmark script to always test the latest registered version without hardcoding paths.$escape$,
  $escape$import wandb
import torch
import onnxruntime as ort
import numpy as np
import time

run = wandb.init(project="onnx-export", job_type="export")

torch.onnx.export(model, dummy_input, "model.onnx", opset_version=17,
                  input_names=["input"], output_names=["output"],
                  dynamic_axes={"input": {0: "batch"}})

artifact = wandb.Artifact("resnet50-onnx", type="model",
                          metadata={"opset": 17, "framework": "pytorch",
                                    "config": dict(run.config)})
artifact.add_file("model.onnx")
run.log_artifact(artifact)

sess = ort.InferenceSession("model.onnx", providers=["CPUExecutionProvider"])
start = time.perf_counter()
for _ in range(100):
    sess.run(None, {"input": np.random.randn(1, 3, 224, 224).astype(np.float32)})
wandb.log({"onnx_latency_ms": (time.perf_counter() - start) / 100 * 1000})
run.finish()$escape$,
  $escape$python$escape$,
