INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2be83da7-07ae-41d0-8326-0b63011a8667',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb + TensorRT — Tracking Quantization Tradeoffs Across Engine Builds$escape$,
  $escape$When building TensorRT engines, INT8 calibration can slash latency by 2–4x but silently erode accuracy. wandb makes this tradeoff visible across every engine variant you ship. Log engine build metadata — precision mode, workspace size, calibration dataset hash — as `wandb.config`, then benchmark each engine and push latency percentiles and task-specific accuracy (mAP, top-1, BLEU) as `wandb.log` metrics. Use `wandb.log({"p50_latency_ms": ..., "p99_latency_ms": ..., "accuracy": ...})` per engine run so the Summary table lets you sort by the Pareto frontier: best accuracy at a given latency budget. Tag runs with `tags=["fp32", "int8", "fp16"]` to filter instantly in the workspace. Store the serialized `.engine` file as a `wandb.Artifact` with `type="trt-engine"` — this pins the exact binary to its benchmark result, so you can `use_artifact()` to redeploy the winning engine without rebuilding. Use `wandb.Table` to log per-layer precision assignments when debugging accuracy regressions from forced INT8 layers.$escape$,
  $escape$import wandb
import tensorrt as trt

run = wandb.init(project="trt-optimization", config={
    "precision": "int8",
    "workspace_gb": 4,
    "calib_batches": 100,
})

# Build engine (assume build_engine() returns (engine, build_time_ms))
engine, build_ms = build_engine(config=wandb.config)

# Benchmark
p50, p99, accuracy = benchmark_engine(engine)
wandb.log({"p50_latency_ms": p50, "p99_latency_ms": p99, "accuracy": accuracy, "build_time_ms": build_ms})

# Persist engine binary as artifact
artifact = wandb.Artifact("resnet50-trt", type="trt-engine")
artifact.add_file("model.engine")
run.log_artifact(artifact)

run.finish()$escape$,
  $escape$python$escape$,
