INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4d65232e-2f42-4cce-af82-3058add788de',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb + Ray Tune — Logging Every HPO Trial Automatically$escape$,
  $escape$When running distributed hyperparameter search with Ray Tune, `WandbLoggerCallback` maps each trial to a separate wandb run inside a shared project — no manual `wandb.init()` per worker needed. Pass it directly to `tune.run()` or `Tuner` and every trial's config, metrics, and system stats stream to wandb in real time.

For distributed training with Ray Train, use the `WandbLoggerCallback` from `ray.air.integrations.wandb`. It initializes wandb on the rank-0 worker only, preventing duplicate metric writes across nodes.

To group a full HPO sweep for comparison, set `group` in the callback's `wandb_init_kwargs`. This surfaces all trials under one sweep-style view in the wandb UI — filter by `trial_id` to isolate any run.

For Ray Serve deployments, instrument your `__call__` handler with `wandb.log()` to track live inference latency and request volume. Use `wandb.init(reinit=False)` at the deployment class level so the run persists across requests without reinitializing on every call.$escape$,
  $escape$from ray import tune
from ray.air.integrations.wandb import WandbLoggerCallback

def train_fn(config):
    for epoch in range(10):
        loss = (config["lr"] - 0.01) ** 2 + epoch * 0.01
        tune.report(loss=loss)

tuner = tune.Tuner(
    train_fn,
    param_space={"lr": tune.loguniform(1e-4, 1e-1)},
    run_config=tune.RunConfig(
        callbacks=[
            WandbLoggerCallback(
                project="byteai-hpo",
                group="ray-tune-sweep",
                log_config=True,
            )
        ]
    ),
)
tuner.fit()$escape$,
  $escape$python$escape$,
