INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fd8f9017-668d-4c53-b412-8839929e53a2',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb — Detecting Model Drift and Performance Degradation in Production$escape$,
  $escape$Production models degrade silently. wandb gives you the primitives to catch it early. Log prediction distributions alongside ground truth using `wandb.log()` at inference time — track metrics like PSI (Population Stability Index) or KL divergence on your output logits across rolling windows. For data drift, log feature statistics per batch and use wandb Tables to diff input distributions between training and serving. Set up `wandb.alert()` to fire when a tracked metric crosses a threshold — e.g., when rolling accuracy drops 5% below your baseline run. Use `wandb.run.summary` to pin your prod baseline metrics, then compare live runs against it programmatically via the wandb API (`api.run(path).summary`). For systematic monitoring, create a dedicated wandb Project per environment (train, staging, prod) and use run tags like `env:prod` to filter dashboards. Pair with W&B Reports to build a drift detection dashboard that auto-refreshes — no separate monitoring stack needed. The key is instrumenting your inference service as a long-lived wandb run, not just training.$escape$,
  $escape$import wandb
from scipy.special import kl_div
import numpy as np

run = wandb.init(project="prod-monitoring", tags=["env:prod"], resume="allow")

def log_prediction_batch(preds: np.ndarray, train_dist: np.ndarray, actuals=None):
    kl = float(np.sum(kl_div(train_dist + 1e-9, preds + 1e-9)))
    payload = {"drift/kl_divergence": kl, "pred/mean": preds.mean(), "pred/std": preds.std()}
    if actuals is not None:
        payload["perf/accuracy"] = float((preds.argmax(1) == actuals).mean())
    wandb.log(payload)
    if kl > 0.2:
        wandb.alert(title="Prediction Drift Detected", text=f"KL divergence spiked to {kl:.3f}")$escape$,
  $escape$python$escape$,
