INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '66ee4185-738e-43a4-92b9-0df99263a236',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Model Registry — Automating CI/CD Evaluation Gates for ML Pipelines$escape$,
  $escape$wandb's Model Registry is the missing piece in ML CI/CD — it lets you version, gate, and promote models via alias rather than hardcoded paths. The pattern: every retraining job logs a `wandb.Artifact` of type `"model"` and stores eval metrics in `artifact.metadata`. Your gate script then fetches the `"production"` alias via `wandb.Api()`, compares metrics, and promotes only if improvement clears the threshold.

Store baseline metrics directly on the artifact at log time: `artifact.metadata = {"eval_accuracy": val}` before `run.log_artifact(artifact)`. This keeps the metric co-located with the model version — no cross-referencing run IDs.

Promotion is a one-liner alias mutation: `artifact.aliases.append("production"); artifact.save()`. Your serving infra polls the `"production"` alias, so it auto-picks up the new version without a redeployment.

Tag training runs with pipeline stage (`ci-retrain`, `ci-eval`) using `run.tags`, then filter via `api.runs(filters={"tags": ["ci-retrain"]})` for full lineage. Pair with `wandb.alert()` inside the eval run to fire Slack notifications on gate failures — keeping humans in the loop only when automation breaks down.$escape$,
  $escape$import wandb

api = wandb.Api()
THRESHOLD = 0.005  # require 0.5% improvement

# Pull production baseline metric from registry artifact
prod = api.artifact("myorg/myproject/model:production")
baseline_acc = prod.metadata["eval_accuracy"]

# Get latest CI retraining run
runs = api.runs("myorg/myproject", filters={"tags": ["ci-retrain"]}, order="-created_at")
new_acc = runs[0].summary.get("eval/accuracy", 0.0)

# Evaluation gate: promote only on meaningful gain
if new_acc > baseline_acc + THRESHOLD:
    candidate = api.artifact("myorg/myproject/model:latest")
    candidate.aliases.append("production")
    candidate.save()
    print(f"Promoted: {new_acc:.4f} vs baseline {baseline_acc:.4f}")
else:
    print(f"Gate failed: {new_acc:.4f} did not clear {baseline_acc + THRESHOLD:.4f}")$escape$,
  $escape$python$escape$,
