INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a20db247-78be-494e-9076-1be8a8f8da8b',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb — Surviving Spot Instance Preemptions Without Losing Training Progress$escape$,
  $escape$Spot instances can cut GPU costs 60–90%, but preemptions kill runs mid-epoch. wandb's resume mechanism makes them viable. Initialize every run with `resume="allow"` and a deterministic `id` derived from your config hash — wandb will reconnect the same run timeline on restart rather than creating orphaned duplicates.

Checkpoint aggressively: save model state to `wandb.run.dir` so it's synced to the artifact store before the instance dies. On restart, pull the latest checkpoint via `wandb.restore()` using the run ID, load it into your model, and continue logging — wandb stitches the step history seamlessly.

For sweep agents on spot clusters, use `wandb agent --count 1` per instance. Each agent picks one sweep trial, completes or crashes, and the sweep scheduler reassigns crashed runs automatically. Pair this with `wandb.log({"gpu_cost_usd": hours * spot_price})` to track real dollar spend per experiment — surfaced directly in the sweep comparison table for cost-per-accuracy tradeoffs.$escape$,
  $escape$import wandb
import hashlib, json

def make_run_id(config: dict) -> str:
    return hashlib.md5(json.dumps(config, sort_keys=True).encode()).hexdigest()[:8]

config = {"lr": 1e-3, "epochs": 50, "model": "resnet50"}

run = wandb.init(
    project="spot-training",
    id=make_run_id(config),
    resume="allow",
    config=config,
)

# Restore latest checkpoint if resuming
if run.resumed:
    ckpt_file = wandb.restore("checkpoint.pt", run_path=run.path)
    model.load_state_dict(torch.load(ckpt_file.name))

for epoch in range(start_epoch, config["epochs"]):
    loss = train_epoch(model, loader)
    torch.save(model.state_dict(), f"{wandb.run.dir}/checkpoint.pt")
    wandb.save("checkpoint.pt")  # sync immediately
    wandb.log({"loss": loss, "epoch": epoch, "gpu_cost_usd": epoch * SPOT_RATE})$escape$,
  $escape$python$escape$,
